// LINEのWebhookからメッセージを取得
const body = $input.first().json.body;

// イベントが存在しない場合はスキップ
if (!body.events || body.events.length === 0) {
  return [];
}

const results = [];

for (const event of body.events) {
  // テキストメッセージのみ処理
  if (event.type !== 'message' || event.message.type !== 'text') {
    continue;
  }

  const text = event.message.text;
  const userId = event.source.userId;
  const replyToken = event.replyToken;

  // 「日報」で始まるメッセージのみ処理
  if (!text.startsWith('日報')) {
    continue;
  }

  // 各フィールドを正規表現で抽出
  const extract = (label, str) => {
    const match = str.match(new RegExp(label + '[：:]\\s*(.+)'));
    return match ? match[1].trim() : null;
  };

  const date        = extract('日付', text);
  const companyName = extract('会社名', text);
  const propertyName = extract('物件名', text);
  const startTime   = extract('開始', text);
  const endTime     = extract('終了', text);
  const breakMin    = extract('休憩', text);
  const workContent = extract('作業内容', text);

  // 必須フィールドチェック
  const missing = [];
  if (!date)         missing.push('日付');
  if (!companyName)  missing.push('会社名');
  if (!propertyName) missing.push('物件名');
  if (!startTime)    missing.push('開始');
  if (!endTime)      missing.push('終了');
  if (!breakMin)     missing.push('休憩');
  if (!workContent)  missing.push('作業内容');

  if (missing.length > 0) {
    results.push({
      json: {
        valid: false,
        replyToken,
        userId,
        errorMessage: `以下の項目が不足しています：\n${missing.join('、')}\n\n正しいフォーマット：\n日報\n日付：YYYY/MM/DD\n会社名：〇〇株式会社\n物件名：〇〇ビル\n開始：09:00\n終了：18:00\n休憩：60\n作業内容：作業の内容`
      }
    });
    continue;
  }

  // 実働時間を計算
  const [sh, sm] = startTime.split(':').map(Number);
  const [eh, em] = endTime.split(':').map(Number);
  const totalMin = (eh * 60 + em) - (sh * 60 + sm) - parseInt(breakMin);
  const workH = Math.floor(totalMin / 60);
  const workM = totalMin % 60;
  const workingTime = `${workH}:${String(workM).padStart(2, '0')}`;

  // 対象ファイル名（年ごと）
  const year = date.split('/')[0];
  const fileName = `稼働表_${year}年.xlsx`;

  results.push({
    json: {
      valid: true,
      replyToken,
      userId,
      date,
      companyName,
      propertyName,
      startTime,
      endTime,
      breakMin: parseInt(breakMin),
      workContent,
      workingTime,
      fileName
    }
  });
}

return results;

// =============================
// 社員マスター設定（LINE UserID → 社員名）
// 社員が増えた場合はここに追加してください
// =============================
const EMPLOYEE_MAP = {
  "Uxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx": "田中太郎",
  "Uyyyyyyyyyyyyyyyyyyyyyyyyyyyyyyyyy": "山田花子"
  // 追加例:
  // "Uzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz": "鈴木一郎",
};
// =============================

const userId = $json.userId;
const employeeName = EMPLOYEE_MAP[userId];

if (!employeeName) {
  return [{
    json: {
      ...$json,
      valid: false,
      errorMessage: `登録されていないLINEアカウントです。\n管理者に連絡してください。\n(UserID: ${userId})`
    }
  }];
}

return [{
  json: {
    ...$json,
    employeeName
  }
}];

// ExcelJSを使用してExcelファイルに行を追加
// ※ 事前にn8nサーバーで `npm install exceljs` が必要です
const ExcelJS = require('exceljs');

const reportData = $('社員確認').first().json;
const binaryData = $input.first().binary?.data;

const workbook = new ExcelJS.Workbook();

// ファイルが存在する場合は読み込み、存在しない場合は新規作成
if (binaryData) {
  const buffer = Buffer.from(binaryData.data, 'base64');
  await workbook.xlsx.load(buffer);
} else {
  // 新規ファイル作成（ファイルが存在しない年の初回）
  console.log(`新規ファイル作成: ${reportData.fileName}`);
}

// 社員シートを取得または作成
let sheet = workbook.getWorksheet(reportData.employeeName);
if (!sheet) {
  sheet = workbook.addWorksheet(reportData.employeeName);

  // ヘッダー行を追加（スタイル付き）
  const headerRow = sheet.addRow([
    '日付', '会社名', '物件名', '開始時間', '終了時間', '休憩(分)', '実働時間', '作業内容'
  ]);

  // ヘッダースタイル設定
  headerRow.eachCell((cell) => {
    cell.font = { bold: true, color: { argb: 'FFFFFFFF' } };
    cell.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF2F5496' }
    };
    cell.alignment = { horizontal: 'center', vertical: 'middle' };
    cell.border = {
      top: { style: 'thin' },
      left: { style: 'thin' },
      bottom: { style: 'thin' },
      right: { style: 'thin' }
    };
  });

  // 列幅設定
  sheet.getColumn(1).width = 12;  // 日付
  sheet.getColumn(2).width = 20;  // 会社名
  sheet.getColumn(3).width = 25;  // 物件名
  sheet.getColumn(4).width = 10;  // 開始時間
  sheet.getColumn(5).width = 10;  // 終了時間
  sheet.getColumn(6).width = 10;  // 休憩(分)
  sheet.getColumn(7).width = 10;  // 実働時間
  sheet.getColumn(8).width = 40;  // 作業内容
}

// 同じ日付のレコードが既に存在するか確認
const existingRow = sheet.getRows(2, sheet.lastRow?.number ?? 1)?.find(row =>
  row.getCell(1).value === reportData.date
);

if (existingRow) {
  // 既存行を更新
  existingRow.getCell(1).value = reportData.date;
  existingRow.getCell(2).value = reportData.companyName;
  existingRow.getCell(3).value = reportData.propertyName;
  existingRow.getCell(4).value = reportData.startTime;
  existingRow.getCell(5).value = reportData.endTime;
  existingRow.getCell(6).value = reportData.breakMin;
  existingRow.getCell(7).value = reportData.workingTime;
  existingRow.getCell(8).value = reportData.workContent;
} else {
  // 新しい行を追加
  const newRow = sheet.addRow([
    reportData.date,
    reportData.companyName,
    reportData.propertyName,
    reportData.startTime,
    reportData.endTime,
    reportData.breakMin,
    reportData.workingTime,
    reportData.workContent
  ]);

  // 罫線設定
  newRow.eachCell((cell) => {
    cell.border = {
      top: { style: 'thin' },
      left: { style: 'thin' },
      bottom: { style: 'thin' },
      right: { style: 'thin' }
    };
    cell.alignment = { vertical: 'middle' };
  });
}

// バッファに書き出し
const buffer = await workbook.xlsx.writeBuffer();
const base64 = Buffer.from(buffer).toString('base64');

return [{
  json: reportData,
  binary: {
    data: {
      data: base64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: reportData.fileName,
      fileExtension: 'xlsx'
    }
  }
}];

// 成功時のLINE返信メッセージ作成
const d = $('社員確認').first().json;

return [{
  json: {
    replyToken: d.replyToken,
    messages: [
      {
        type: 'text',
        text: `✅ 日報を記録しました\n\n👷 ${d.employeeName}\n📅 ${d.date}\n🏢 ${d.companyName}\n🏗️ ${d.propertyName}\n⏰ ${d.startTime} ～ ${d.endTime}（休憩${d.breakMin}分）\n⚡ 実働：${d.workingTime}\n📝 ${d.workContent}`
      }
    ]
  }
}];

// エラー時（フォーマット不正 or 未登録ユーザー）のLINE返信
const d = $input.first().json;

return [{
  json: {
    replyToken: d.replyToken,
    messages: [
      {
        type: 'text',
        text: `❌ ${d.errorMessage}`
      }
    ]
  }
}];
